#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if(!(cin>>n)) return 0;
    vector<int> a(n);
    for(int i=0;i<n;++i) cin>>a[i];
    int maxReach=0;
    for(int i=0;i<n;++i){
        if(i>maxReach){
            cout<<"NO";
            return 0;
        }
        maxReach = max(maxReach, i + a[i]);
        if(maxReach>=n-1){
            cout<<"YES";
            return 0;
        }
    }
    cout<<(maxReach>=n-1?"YES":"NO");
    return 0;
}
